import {
  circle, ellipse, rectangle, rounded_rectangle, polygon, triangle,
  segment, arc, ring, union, intersection, difference,
  dilate, erode, shell, render,
} from '../../src/index.js';

// ── Palette ─────────────────────────────────────────────────────────────────
const OUTLINE     = [32, 24, 20];
const TABLE_TOP   = [210, 185, 148];   // warm oak
const TABLE_SHADE = [180, 152, 112];   // table shadow band
const PLATE_WHITE = [245, 240, 232];   // off-white china
const PLATE_RIM   = [230, 220, 205];   // rim glaze
const WINE_GLASS  = [200, 225, 215];   // pale aqua glass
const WINE_LIQUID = [148, 40, 55];     // burgundy wine
const NAPKIN_C    = [195, 80, 65];     // terracotta linen
const FORK_KNIFE  = [190, 185, 178];   // silver cutlery
const BREAD_C     = [220, 178, 110];   // warm bread
const BREAD_CRUST = [168, 118, 62];    // darker crust
const HERB_C      = [82, 130, 72];     // parsley green
const CANDLE_WAX  = [248, 235, 195];   // ivory wax
const FLAME_OUT   = [240, 165, 40];    // outer flame
const FLAME_IN    = [255, 230, 120];   // inner flame
const CANDLESTICK = [190, 160, 70];    // brass
const BG_TOP      = [245, 238, 225];
const BG_BOT      = [225, 215, 195];

// ── Table surface ────────────────────────────────────────────────────────────
// Elliptical table top viewed in slight perspective
const tableSurface = ellipse(1.15, 0.55, [0, -0.08]);
const tableEdge    = difference(
  tableSurface,
  ellipse(1.09, 0.48, [0, -0.10]),
);
const shadowBand   = intersection(
  tableSurface,
  rectangle([2.4, 0.06], [0, -0.56]),
);

// ── Dinner plate (center) ────────────────────────────────────────────────────
const plateOuter  = ellipse(0.30, 0.135, [0, -0.10]);
const plateInner  = ellipse(0.22, 0.100, [0, -0.10]);
const plateWell   = ellipse(0.17, 0.075, [0, -0.10]);

// ── Wine glass ───────────────────────────────────────────────────────────────
// bowl = ellipse, stem = segment, base = thin ellipse
const glassBowl   = ellipse(0.075, 0.09, [0.52, 0.05]);
const glassTop    = intersection(glassBowl, rectangle([0.18, 0.09], [0.52, 0.10]));
const glassStem   = segment([0.52, -0.04], [0.52, -0.20], 0.007);
const glassBase   = ellipse(0.065, 0.018, [0.52, -0.20]);
const glassBody   = union(glassBowl, glassStem, glassBase);
// wine level – intersection clips to bowl shape
const wineFill    = intersection(
  glassBowl,
  rectangle([0.20, 0.07], [0.52, -0.015]),
);

// ── Napkin (folded triangle, left of plate) ──────────────────────────────────
const napkin = polygon([
  [-0.44, -0.18],
  [-0.18, -0.18],
  [-0.28,  0.08],
]);
const napkinFold = intersection(
  napkin,
  polygon([
    [-0.42, -0.08],
    [-0.22, -0.08],
    [-0.30,  0.06],
  ]),
);

// ── Fork (left) ──────────────────────────────────────────────────────────────
function fork(cx, cy) {
  const handle = segment([cx, cy - 0.23], [cx, cy + 0.08], 0.010);
  const tine1  = segment([cx - 0.015, cy + 0.07], [cx - 0.015, cy + 0.23], 0.005);
  const tine2  = segment([cx,          cy + 0.07], [cx,          cy + 0.23], 0.005);
  const tine3  = segment([cx + 0.015, cy + 0.07], [cx + 0.015, cy + 0.23], 0.005);
  const tineBase = rectangle([0.050, 0.015], [cx, cy + 0.075]);
  return union(handle, tineBase, tine1, tine2, tine3);
}
const forkShape = fork(-0.38, -0.10);

// ── Knife (right) ────────────────────────────────────────────────────────────
function knife(cx, cy) {
  const handle  = segment([cx, cy - 0.23], [cx, cy + 0.05], 0.012);
  const bolster = ellipse(0.016, 0.020, [cx, cy + 0.06]);
  const blade   = polygon([
    [cx - 0.008, cy + 0.06],
    [cx + 0.008, cy + 0.06],
    [cx + 0.004, cy + 0.27],
    [cx - 0.008, cy + 0.27],
  ]);
  return union(handle, bolster, blade);
}
const knifeShape = knife(0.38, -0.10);

// ── Bread roll (upper left of plate) ─────────────────────────────────────────
const breadRoll  = ellipse(0.088, 0.062, [-0.20, 0.13]);
const breadScore = shell(
  intersection(breadRoll, rectangle([0.20, 0.020], [-0.20, 0.13])),
  0.005,
);
const breadHighlight = intersection(
  breadRoll,
  ellipse(0.045, 0.028, [-0.22, 0.17]),
);

// ── Herb sprig on plate ───────────────────────────────────────────────────────
const herbStem = segment([-0.03, -0.14], [0.04, -0.06], 0.005);
const leaf1    = ellipse(0.018, 0.010, [0.00, -0.09]).rotate( 0.5);
const leaf2    = ellipse(0.018, 0.010, [0.02, -0.07]).rotate(-0.3);
const herb     = union(herbStem, leaf1, leaf2);

// ── Candle + candlestick (right background) ───────────────────────────────────
const stickBase   = ellipse(0.052, 0.018, [0.70, -0.27]);
const stickColumn = segment([0.70, -0.27], [0.70, -0.12], 0.016);
const stickCup    = ellipse(0.030, 0.015, [0.70, -0.12]);
const candleBody  = rounded_rectangle([0.032, 0.13], 0.006, [0.70, 0.01]);
const flameOuter  = ellipse(0.018, 0.036, [0.70, 0.105]);
const flameInner  = ellipse(0.009, 0.022, [0.70, 0.100]);
const wickLine    = segment([0.70, 0.068], [0.70, 0.082], 0.003);
const candleStick = union(stickBase, stickColumn, stickCup);

// ── Clip everything to table surface ────────────────────────────────────────
function onTable(sdf) {
  return intersection(sdf, tableSurface);
}

// ── Layers ───────────────────────────────────────────────────────────────────
const layers = [
  // table fill
  { sdf: tableSurface,               color: TABLE_TOP },
  { sdf: dilate(tableSurface,0.025), color: OUTLINE },
  { sdf: tableSurface,               color: TABLE_TOP },
  { sdf: shadowBand,                 color: TABLE_SHADE },
  { sdf: tableEdge,                  color: TABLE_SHADE },

  // napkin
  { sdf: onTable(dilate(napkin,0.016)), color: OUTLINE },
  { sdf: onTable(napkin),              color: NAPKIN_C },
  { sdf: onTable(napkinFold),          color: [210, 92, 78] },

  // fork
  { sdf: onTable(dilate(forkShape,0.012)), color: OUTLINE },
  { sdf: onTable(forkShape),               color: FORK_KNIFE },

  // knife
  { sdf: onTable(dilate(knifeShape,0.012)), color: OUTLINE },
  { sdf: onTable(knifeShape),               color: FORK_KNIFE },

  // plate layers
  { sdf: onTable(dilate(plateOuter,0.020)), color: OUTLINE },
  { sdf: onTable(plateOuter),               color: PLATE_RIM },
  { sdf: onTable(plateInner),               color: PLATE_WHITE },
  { sdf: onTable(plateWell),                color: [255, 252, 248] },

  // herb on plate
  { sdf: onTable(herb), color: HERB_C },

  // bread roll
  { sdf: onTable(dilate(breadRoll,0.014)), color: BREAD_CRUST },
  { sdf: onTable(breadRoll),              color: BREAD_C },
  { sdf: onTable(breadScore),             color: BREAD_CRUST },
  { sdf: onTable(breadHighlight),         color: [235, 200, 135] },

  // wine glass
  { sdf: onTable(dilate(glassBody,0.015)), color: OUTLINE },
  { sdf: onTable(glassBody),               color: WINE_GLASS },
  { sdf: onTable(wineFill),                color: WINE_LIQUID },
  { sdf: onTable(shell(glassBowl, 0.008)), color: [220, 240, 230] },

  // candlestick
  { sdf: onTable(dilate(candleStick,0.012)), color: OUTLINE },
  { sdf: onTable(candleStick),               color: CANDLESTICK },
  { sdf: onTable(dilate(candleBody,0.012)),  color: OUTLINE },
  { sdf: onTable(candleBody),                color: CANDLE_WAX },
  { sdf: onTable(wickLine),                  color: OUTLINE },
  { sdf: dilate(flameOuter,0.004),           color: [200, 110, 20] },
  { sdf: flameOuter,                         color: FLAME_OUT },
  { sdf: flameInner,                         color: FLAME_IN },
];

// ── Render ───────────────────────────────────────────────────────────────────
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.2,
  background: { top: BG_TOP, bottom: BG_BOT },
});
```

**Composition notes:** The scene is built around a single elliptical table viewed at a slight bird's-eye perspective — the major/minor axis ratio (~2:1) implies a round table in realistic foreshortening. Everything is clipped via `intersection(..., tableSurface)` so no element spills beyond the table edge, echoing the "decoration clipped to silhouette" idiom from `boat.js`.

The **visual hierarchy** is plate (center) → wine glass (right) → napkin + cutlery (flanking) → bread roll (upper left) → candle (background right), roughly following a classic Western place-setting layout. Outline thickness is graded: 0.020–0.025 for the table rim and plate, 0.012–0.016 for the smaller elements, giving depth. The candle flame is intentionally left **without** a dark outline (soft glow objects never get outlines), following the same no-outline-on-luminous-sources rule from `boat.js`'s sun. Palette is anchored to a warm terracotta / oak / burgundy register, suitable for a Taschen cookbook spread or a *Bon Appétit* editorial illustration.
